import{_ as t,c as e,o as r,ae as o}from"./chunks/framework.B7Y1jjX-.js";const u=JSON.parse('{"title":"","description":"","frontmatter":{},"headers":[],"relativePath":"notes/学习/学校竞赛、项目/数学建模/课程知识/Gamma回归.md","filePath":"notes/学习/学校竞赛、项目/数学建模/课程知识/Gamma回归.md"}'),l={name:"notes/学习/学校竞赛、项目/数学建模/课程知识/Gamma回归.md"};function p(n,a,i,s,_,g){return r(),e("div",null,[...a[0]||(a[0]=[o('<p>![[Pasted image 20250907095615.png]] ![[Pasted image 20250907095815.png]] ![[Pasted image 20250907095833.png]] ![[Pasted image 20250907100009.png]]</p><h2 id="_1-伽马回归的本质" tabindex="-1">1. 伽马回归的本质 <a class="header-anchor" href="#_1-伽马回归的本质" aria-label="Permalink to &quot;1. 伽马回归的本质&quot;">​</a></h2><ul><li><p><strong>伽马回归</strong>常用于建模<strong>正值且右偏分布</strong>的响应变量（如生物、医学中的浓度、时间、费用等）。</p></li><li><p>一般采用**广义线性模型（GLM）**框架，<strong>伽马分布</strong>为因变量分布，**连接函数（link function）**常用倒数（inverse）或对数（log）。</p></li></ul><hr><h2 id="_2-公式各部分含义" tabindex="-1">2. 公式各部分含义 <a class="header-anchor" href="#_2-公式各部分含义" aria-label="Permalink to &quot;2. 公式各部分含义&quot;">​</a></h2><h3 id="_1-线性预测部分" tabindex="-1">1）<strong>线性预测部分</strong> <a class="header-anchor" href="#_1-线性预测部分" aria-label="Permalink to &quot;1）**线性预测部分**&quot;">​</a></h3><p>η=β0+β1X1+⋯+βpXp\\eta = \\beta_0 + \\beta_1 X_1 + \\cdots + \\beta_p X_pη=β0​+β1​X1​+⋯+βp​Xp​</p><ul><li><p>β0\\beta_0β0​：截距</p></li><li><p>β1,⋯ ,βp\\beta_1, \\cdots, \\beta_pβ1​,⋯,βp​：各自变量的回归系数</p></li><li><p>X1,⋯ ,XpX_1, \\cdots, X_pX1​,⋯,Xp​：自变量（如孕周、BMI、年龄等）</p></li></ul><h3 id="_2-连接函数" tabindex="-1">2）<strong>连接函数</strong> <a class="header-anchor" href="#_2-连接函数" aria-label="Permalink to &quot;2）**连接函数**&quot;">​</a></h3><p>μ=1η=1β0+β1X1+⋯+βpXp\\mu = \\frac{1}{\\eta} = \\frac{1}{\\beta_0 + \\beta_1 X_1 + \\cdots + \\beta_p X_p}μ=η1​=β0​+β1​X1​+⋯+βp​Xp​1​</p><ul><li><p>这里采用<strong>倒数连接函数（inverse link）</strong>，即：</p><ul><li><p>期望值μ\\muμ（即预测的Y染色体浓度）等于线性部分的倒数</p></li><li><p>这样可以确保μ&gt;0\\mu &gt; 0μ&gt;0，符合伽马分布只能取正值的特性</p></li></ul></li></ul><h3 id="_3-实际含义" tabindex="-1">3）<strong>实际含义</strong> <a class="header-anchor" href="#_3-实际含义" aria-label="Permalink to &quot;3）**实际含义**&quot;">​</a></h3><ul><li><p>μ\\muμ表示<strong>因变量的期望值</strong>，比如你建模的<strong>Y染色体浓度的预测值</strong></p></li><li><p>βi\\beta_iβi​为正/负，说明自变量对μ\\muμ的正向或负向影响</p></li></ul><hr><h2 id="_3-对建模的实际意义" tabindex="-1">3. 对建模的实际意义 <a class="header-anchor" href="#_3-对建模的实际意义" aria-label="Permalink to &quot;3. 对建模的实际意义&quot;">​</a></h2><ul><li><p>如果βk\\beta_kβk​为正，则对应的自变量XkX_kXk​<strong>增加</strong>会导致分母<strong>变大</strong>，从而μ\\muμ<strong>变小</strong>。</p></li><li><p>如果βk\\beta_kβk​为负，则XkX_kXk​增加会使分母变小，μ\\muμ变大。</p></li><li><p>这种关系和一般的线性回归直接加法不同，<strong>方向要反着理解</strong>！</p></li></ul><hr><h2 id="_4-其他常见形式" tabindex="-1">4. 其他常见形式 <a class="header-anchor" href="#_4-其他常见形式" aria-label="Permalink to &quot;4. 其他常见形式&quot;">​</a></h2><p>实际上，伽马回归还常用<strong>对数连接函数</strong>，即：</p><p>log⁡(μ)=β0+β1X1+⋯+βpXp\\log(\\mu) = \\beta_0 + \\beta_1 X_1 + \\cdots + \\beta_p X_plog(μ)=β0​+β1​X1​+⋯+βp​Xp​</p><p>这时μ=exp⁡(β0+...)\\mu = \\exp(\\beta_0 + ...)μ=exp(β0​+...)。<br> 你的结果是<strong>倒数连接</strong>（inverse link）的写法。</p><hr><h2 id="_5-中文简要总结" tabindex="-1">5. 中文简要总结 <a class="header-anchor" href="#_5-中文简要总结" aria-label="Permalink to &quot;5. 中文简要总结&quot;">​</a></h2><ul><li><p><strong>伽马回归公式</strong>中，μ=1/(β0+β1X1+...+βpXp)\\mu = 1/(\\beta_0 + \\beta_1 X_1 + ... + \\beta_p X_p)μ=1/(β0​+β1​X1​+...+βp​Xp​) 表示<strong>因变量均值由自变量线性组合的倒数决定</strong>。</p></li><li><p>每个自变量对因变量的影响方向，要结合分母和倒数的关系进行解读。</p></li></ul>',24)])])}const d=t(l,[["render",p]]);export{u as __pageData,d as default};
